import{_ as e,c as t,o as a,a4 as i}from"./chunks/framework.nQaBHiNx.js";const h=JSON.parse('{"title":"数据结构 高级数据结构","description":"","frontmatter":{},"headers":[],"relativePath":"computer/data-structure/advance/index.md","filePath":"computer/data-structure/advance/index.md"}'),r={name:"computer/data-structure/advance/index.md"},l=i('<h1 id="数据结构-高级数据结构" tabindex="-1">数据结构 高级数据结构 <a class="header-anchor" href="#数据结构-高级数据结构" aria-label="Permalink to &quot;数据结构 高级数据结构&quot;">​</a></h1><ul><li><p>并查集 在计算机科学中，并查集（英文：Disjoint-set data structure，直译为不交集数据结构）是一种数据结构，用于处理一些不交集（Disjoint sets，一系列没有重复元素的集合）的合并及查询问题。</p></li><li><p>跳表 跳表全称叫做跳跃表，简称跳表。 跳表是一个随机化的数据结构，实质就是一种可以进行二分查找的有序链表。</p></li><li><p>块状链表</p></li><li><p>红黑树 红黑树（Red Black Tree） 是一种自平衡二叉查找树，是在计算机科学中用到的一种数据结构，典型的用途是实现关联数组。</p></li><li><p>前缀树 在计算机科学中，trie，又称前缀树或字典樹，是一种有序树，用于保存关联数组，其中的键通常是字符串。</p></li><li><p>后缀树 后缀树提出的目的是用来支持有效的字符串匹配和查询</p></li><li><p>线段树 线段树是一种二叉搜索树，与区间树相似，它将一个区间划分成一些单元区间，每个单元区间对应线段树中的一个叶结点</p></li><li><p>伸展树 伸展树（Splay Tree），也叫分裂树，是一种二叉排序树，它能在O(log n)内完成插入、查找和删除操作。</p></li></ul>',2),c=[l];function o(s,n,p,d,_,u){return a(),t("div",null,c)}const f=e(r,[["render",o]]);export{h as __pageData,f as default};
